+                    as usize;
+            pos += 4;
+            if pos + name_len > data.len() {
+                return Err(StoreError::GenericError(
+                    "ERR Invalid dump data".to_string(),
+                ));
+            }
+            let name = String::from_utf8_lossy(&data[pos..pos + name_len]).to_string();
+            pos += name_len;
+
+            if pos + 4 > data.len() {
